var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그 존재야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきたあの存在だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this being, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 존재와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まであの存在と共にいることを。","ENG":"that you'll be with this being, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"오, 마침 부탁할 게 있었는데 잘 됐다.","JPN":"あっ、ちょうどよかった。頼みたいことがあるんだ。","ENG":"Oh, perfect timing. I was just about to ask you for something.","TWN":"哦，我正好有件事要拜託你。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네 녀석도 알다시피, 이 몸이 간만에 다시 작품활동을 시작하게 됐잖냐?","JPN":"ほら、私、久しぶりに創作活動を再開したじゃん。","ENG":"You know I've picked up writing again after ages, right?","TWN":"你也知道，我不是久違地重新開始創作了嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"요즘 대세는 멀티버스니까, 한 태스크포스 사장을 사랑하게 된 다중우주 여인들의 피 튀기는 경쟁을 그린… 뭐 그렇고 그런 내용을 이번 시즌에서 다뤄볼까 하는데…","JPN":"最近はマルチバースってのが流行りだから、とあるタスクフォースの社長に恋する、多元宇宙の女性たちの苛烈な戦いを描いた……みたいな内容を今シーズンにやってみようと思ってるんだけど。","ENG":"Multiverse stories are hot right now, so I figured this season I'd do one about women from across dimensions falling for a TASKFORCE CEO... and tearing each other apart over him...","TWN":"最近的流行趨勢是多重宇宙論，所以想講述一群愛上特遣勢力老闆的女人激烈的競爭…我在思考這一季要描述這樣的內容…"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"어때? 재밌겠지?","JPN":"どう？　面白そうでしょ？","ENG":"Well? Sounds exciting, doesn't it?","TWN":"怎麼樣？應該很有趣吧？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"응…? 주인공인 남자, 누굴 모티브로 한 거냐구?","JPN":"うん……？　主人公の男は誰をモデルにしたのかって？","ENG":"Hmm...? Who's the male lead based on, you ask?","TWN":"嗯…？你問我男主角的原型是誰？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐어… 여성 직원을 압도적으로 많이 채용하고 로봇 황금상에 광적으로 집착한다는 면에선 어느 정도 널 참고한 게 있긴 하다만…","JPN":"まあ……女性職員を圧倒的に多く採用して、ロボットの黄金像に異常な執着を見せるところは、ある程度あなたを参考にしてるけど……","ENG":"Weeell... maybe I borrowed a bit from you. Y'know, how you hire a ridiculous number of female employees and obsess over your shiny golden robot statue...","TWN":"那個…雖然在僱用大量女性員工和瘋狂執著於機器人黃金雕像這方面，某種程度上參考了你……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"으앗! 알겠어! 네 이야기로 각색 안 할 테니까 꼬리는 내려놓고 얘기해!","JPN":"うわっ！　わ、分かったよ！　あなたのネタは使わないから、尻尾は放して！","ENG":"Whoa! Okay! I won't adapt it from your life, just let go of my tail already!","TWN":"呃啊！知道了！我不會拿你的故事改編，先放下我的尾巴再說！"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"쳇, 아쉽구만. 감옥에서 생각해본 것들 중에 제일 자신 있는 타이틀이었는데.","JPN":"ちっ、残念。刑務所で考えたストーリーの中で一番の自信作だったのに。","ENG":"Tch, what a shame. It was the best title I'd come up with during my prison days.","TWN":"嘖，真可惜，這可是我在監獄裡想過標題中最有自信的一個。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"아무 말도 하지 않는다","JPN":"何も言わない","ENG":"Say nothing","TWN":"不發一語"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 자넬 아케론에 가둔 것을 원망하나?","JPN":"私が君をアケロンに閉じ込めたことを恨んでいるのか？","ENG":"Do you resent me for locking you in Acheron?","TWN":"你埋怨我把你關在艾卡倫嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네 녀석… 그런 오해를 할 정도로 이 소재가 마음에 안 든 거냐?","JPN":"あなた……そんな誤解をしてしまうほど、このネタが嫌だった？","ENG":"Hey, wait... you mean you hated my idea that much?","TWN":"你這傢伙…難道這個素材讓你不滿意到還產生那種誤會嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"유혹의 함교를 한창 집필하고 있을 적에, 레쉬라는 로봇 간수 녀석이 나한테 묻더라.","JPN":"誘惑の艦橋を書いてたとき、レーシーっていうロボットの看守に聞かれたの。","ENG":"Back when I was deep into writing The Bridge of Seduction, one of the robot guards called Rash asked me something.","TWN":"我在寫誘惑的艦橋那時候，一個叫萊西的機器人獄卒問我。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"수감자님은 무슨 죄를 저질러서 지구 밖까지 쫓겨난 거냐고.","JPN":"どんな罪を犯して、地球の外に追い出されたんですかって。","ENG":"She said, \\"What crime did you commit to get banished beyond Earth?\\"","TWN":"受刑人是犯下什麼罪才被趕出地球。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래서 대답해줬지.","JPN":"だから答えてあげたよ。","ENG":"And I told her straight.","TWN":"所以我就回答他。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"세상을 구하려는 남자가 있고, 내가 그 녀석의 계획을 망칠 예정이라 내 발로 들어왔다- 라고 말이야.","JPN":"世界を救おうとしている男がいるんだけど、私がそいつの計画を台無しにする予定だから、自分の意志でここに来たんだよって。","ENG":"There was a man trying to save the world, and I walked in on my own just to wreck his grand plan.","TWN":"有個男人想拯救世界，而我打算破壞那傢伙的計畫，就自己進來了。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"사람은 대개 자기 스스로를 통제할 수 있다는 오만에 빠져 살지만, 우린 겪어봐서 알잖냐?","JPN":"人って自分自身をコントロールできるなんて傲慢にも思っているけど、私たちは経験してみたから分かるじゃん。","ENG":"Most people live under the illusion they can control themselves, but we both know better, don't we?","TWN":"人大多沉浸在能自我控制的傲慢之中，但我們經歷過，不是知道嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"닥쳐올 시대의 격동 앞에 이성이니 의지니 하는 것들은 한철 갈대나 다름없음을.","JPN":"迫ってくる時代の激動を前にして、理性とか意志みたいなものは何の役にも立たないってことが。","ENG":"When the age of upheaval hits, reason and will are nothing more than reeds in the storm.","TWN":"在即將到來的時代劇變面前，所謂理性和意志都和蘆葦沒有兩樣。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네가 날 가둬놓지 않았다면 난 무슨 수를 써서라도 [그 아이들]을 살리려 했을 거다.","JPN":"あなたが私を閉じ込めなかったら、私はどんな手を使ってても「あの子たち」を助けようとしてた。","ENG":"If you hadn't locked me up, I'd have done whatever it took to save [those children].","TWN":"要不是你把我關起來，我應該會想盡辦法拯救[那些孩子]。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"결코 완성되지 못할 운명을 억지로 붙잡아봐야, 고통만 길어질 뿐이란 걸 알면서도… 난 그렇게 하고 말았을 거야.","JPN":"決して完成されない運命を無理やり引き止めても、苦痛が長引くだけだって分かってるのに……それでも、そうしていたと思う。","ENG":"Even though I knew clinging to an unfinished fate would only drag out the pain... I still would have done it.","TWN":"明知道就算硬是抓住無法完成的命運，只會讓痛苦延長…但我最終還是會那麼做。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};